import{_ as a,o as t,c as s,ag as i}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Email Routing","description":"","frontmatter":{},"headers":[],"relativePath":"features/email-routing.md","filePath":"features/email-routing.md"}'),n={name:"features/email-routing.md"};function o(r,e,l,d,c,p){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="email-routing" tabindex="-1">Email Routing <a class="header-anchor" href="#email-routing" aria-label="Permalink to &quot;Email Routing&quot;">​</a></h1><p>Email routing allows you to send different emails through different SMTP connections based on conditional rules. This is useful when you need to separate transactional emails, marketing emails, and internal notifications across dedicated providers.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Routing rules are evaluated every time WordPress sends an email. SendGrail inspects the email data and checks it against your defined rules in priority order. The <strong>first matching rule wins</strong> -- its assigned connection is used instead of the default.</p><p>If no rules match, the email is sent through the default connection.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Routing rules are evaluated in <code>MailerService.configure()</code> after the email data (recipients, subject, headers) is fully built but before the email is handed off to the SMTP transport.</p></div><h2 id="rule-structure" tabindex="-1">Rule Structure <a class="header-anchor" href="#rule-structure" aria-label="Permalink to &quot;Rule Structure&quot;">​</a></h2><p>Each routing rule consists of the following components:</p><table tabindex="0"><thead><tr><th>Component</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>A descriptive label for the rule</td></tr><tr><td><strong>Priority</strong></td><td>Numeric value controlling evaluation order (lower number = higher priority)</td></tr><tr><td><strong>Field</strong></td><td>The email property to evaluate</td></tr><tr><td><strong>Operator</strong></td><td>The comparison method</td></tr><tr><td><strong>Value</strong></td><td>The value to match against</td></tr><tr><td><strong>Connection</strong></td><td>The SMTP connection to use when the rule matches</td></tr></tbody></table><h2 id="fields" tabindex="-1">Fields <a class="header-anchor" href="#fields" aria-label="Permalink to &quot;Fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Behavior</th></tr></thead><tbody><tr><td><code>to_email</code></td><td>Recipient email address</td><td>Checks <strong>all</strong> recipients (To, CC, BCC). Matches if <strong>any</strong> recipient matches the condition.</td></tr><tr><td><code>from_email</code></td><td>Sender email address</td><td>Checks the From address of the outgoing email.</td></tr><tr><td><code>subject</code></td><td>Email subject line</td><td>Checks the subject text.</td></tr><tr><td><code>header</code></td><td>Email header</td><td>Value format must be <code>Header-Name: value</code>. Checks both the header name and its value.</td></tr></tbody></table><h2 id="operators" tabindex="-1">Operators <a class="header-anchor" href="#operators" aria-label="Permalink to &quot;Operators&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th><th>Case Sensitivity</th></tr></thead><tbody><tr><td><code>equals</code></td><td>Exact match</td><td>Case-insensitive</td></tr><tr><td><code>contains</code></td><td>Substring match</td><td>Case-insensitive</td></tr><tr><td><code>starts_with</code></td><td>Prefix match</td><td>Case-insensitive</td></tr><tr><td><code>ends_with</code></td><td>Suffix match</td><td>Case-insensitive</td></tr><tr><td><code>regex</code></td><td>Regular expression match</td><td>Case-sensitive (use <code>(?i)</code> flag for insensitive)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>All operators except <code>regex</code> are case-insensitive by default. For regex rules, prepend <code>(?i)</code> to your pattern if you need case-insensitive matching.</p></div><h2 id="priority-based-evaluation" tabindex="-1">Priority-Based Evaluation <a class="header-anchor" href="#priority-based-evaluation" aria-label="Permalink to &quot;Priority-Based Evaluation&quot;">​</a></h2><p>Rules are sorted by their priority value (ascending) and evaluated in that order. The first rule that matches the email determines which connection is used.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Priority 1: to_email contains @company.com    -&gt; Internal SMTP</span></span>
<span class="line"><span>Priority 2: subject contains &quot;order&quot;          -&gt; Postmark</span></span>
<span class="line"><span>Priority 3: from_email equals news@site.com   -&gt; Brevo</span></span>
<span class="line"><span>Default:                                      -&gt; Gmail</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If two rules have the same priority, their evaluation order among themselves is not guaranteed. Assign distinct priority values to ensure predictable behavior.</p></div><h2 id="enabling-and-disabling-rules" tabindex="-1">Enabling and Disabling Rules <a class="header-anchor" href="#enabling-and-disabling-rules" aria-label="Permalink to &quot;Enabling and Disabling Rules&quot;">​</a></h2><p>Individual rules can be enabled or disabled without deleting them. Disabled rules are skipped during evaluation. This is useful for temporarily suspending a rule during testing or maintenance.</p><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><h3 id="woocommerce-order-emails-via-postmark" tabindex="-1">WooCommerce Order Emails via Postmark <a class="header-anchor" href="#woocommerce-order-emails-via-postmark" aria-label="Permalink to &quot;WooCommerce Order Emails via Postmark&quot;">​</a></h3><p>Route all WooCommerce order notifications through a dedicated transactional email provider for higher deliverability:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Field:    subject</span></span>
<span class="line"><span>Operator: contains</span></span>
<span class="line"><span>Value:    order</span></span>
<span class="line"><span>Connection: Postmark</span></span></code></pre></div><h3 id="newsletters-via-brevo" tabindex="-1">Newsletters via Brevo <a class="header-anchor" href="#newsletters-via-brevo" aria-label="Permalink to &quot;Newsletters via Brevo&quot;">​</a></h3><p>Route marketing emails sent from a specific address through a bulk-sending provider:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Field:    from_email</span></span>
<span class="line"><span>Operator: equals</span></span>
<span class="line"><span>Value:    newsletter@yoursite.com</span></span>
<span class="line"><span>Connection: Brevo</span></span></code></pre></div><h3 id="internal-notifications-via-gmail" tabindex="-1">Internal Notifications via Gmail <a class="header-anchor" href="#internal-notifications-via-gmail" aria-label="Permalink to &quot;Internal Notifications via Gmail&quot;">​</a></h3><p>Route all emails to your company domain through Gmail:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Field:    to_email</span></span>
<span class="line"><span>Operator: ends_with</span></span>
<span class="line"><span>Value:    @yourcompany.com</span></span>
<span class="line"><span>Connection: Gmail</span></span></code></pre></div><h3 id="custom-header-routing" tabindex="-1">Custom Header Routing <a class="header-anchor" href="#custom-header-routing" aria-label="Permalink to &quot;Custom Header Routing&quot;">​</a></h3><p>Route emails tagged with a specific header (useful for plugins that add custom headers):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Field:    header</span></span>
<span class="line"><span>Operator: contains</span></span>
<span class="line"><span>Value:    X-Mail-Type: transactional</span></span>
<span class="line"><span>Connection: Postmark</span></span></code></pre></div><details class="details custom-block"><summary>How to verify your routing rules</summary><p>Use the <a href="/features/test-simulate#email-simulation">Email Simulation</a> feature to dry-run an email and see which connection and routing rule would be applied, without actually sending a message.</p></details>`,34)])])}const m=a(n,[["render",o]]);export{h as __pageData,m as default};
